    // --- OperationPaginator encrypt/decrypt ---

    fn make_operation_paginator() -> OperationPaginator<FixedKeyService, FixedKeyService> {
        let key_id = Uuid::new_v4();
        let encrypted_key = [99u8; PAGINATION_KEY_SIZE];
        let svc = FixedKeyService::new(key_id, encrypted_key);
        OperationPaginator::new(&"test-service", &"ListItems", svc.clone(), svc).unwrap()
    }

    #[test_log::test(tokio::test)]
    async fn test_encrypt_decrypt_roundtrip_string() {
        let paginator = make_operation_paginator();
        let state = "cursor_value";
        let token = paginator.encrypt_token(&state).await.unwrap();
        let decoded: String = paginator.decrypt_token(&token).await.unwrap();
        assert_eq!(decoded, state);
    }

    #[test_log::test(tokio::test)]
    async fn test_encrypt_decrypt_roundtrip_struct() {
        #[derive(Debug, Deserialize, Serialize, PartialEq)]
        struct PaginationState {
            last_id: u64,
            marker: String,
        }

        let paginator = make_operation_paginator();
        let state = PaginationState {
            last_id: 12345,
            marker: "alice".to_string(),
        };
        let token = paginator.encrypt_token(&state).await.unwrap();
        let decoded: PaginationState = paginator.decrypt_token(&token).await.unwrap();
        assert_eq!(decoded, state);
    }

    #[test_log::test(tokio::test)]
    async fn test_decrypt_empty_token() {
        let paginator = make_operation_paginator();
        let result: Result<String, _> = paginator.decrypt_token("").await;
        assert!(result.is_err());
    }

    #[test_log::test(tokio::test)]
    async fn test_decrypt_wrong_version_byte() {
        let paginator = make_operation_paginator();
        // Version 'X' (0x58) is not V0 ('0' = 0x30)
        let result: Result<String, _> = paginator.decrypt_token("Xinvalid").await;
        let err = result.unwrap_err();
        assert!(err.to_string().contains("version"), "{err}");
    }

    #[test_log::test(tokio::test)]
    async fn test_decrypt_too_short_payload() {
        let paginator = make_operation_paginator();
        // Version byte '0' followed by a base64-encoded payload shorter than 28 bytes
        let short = format!("0{}", URL_SAFE_NO_PAD.encode(b"tooshort"));
        let result: Result<String, _> = paginator.decrypt_token(&short).await;
        assert!(result.is_err());
    }

    #[test_log::test(tokio::test)]
    async fn test_decrypt_wrong_aad() {
        let key_id = Uuid::new_v4();
        let encrypted_key = [99u8; PAGINATION_KEY_SIZE];
        let svc = FixedKeyService::new(key_id, encrypted_key);

        let paginator1 = OperationPaginator::new(&"test-service", &"ListItems", svc.clone(), svc.clone()).unwrap();
        let paginator2 = OperationPaginator::new(&"test-service", &"ListOtherItems", svc.clone(), svc).unwrap();

        let token = paginator1.encrypt_token(&"some_cursor").await.unwrap();
        let result: Result<String, _> = paginator2.decrypt_token(&token).await;
        assert!(result.is_err());
    }

    #[test_log::test(tokio::test)]
    async fn test_decrypt_unknown_key_id() {
        let key_id = Uuid::new_v4();
        let other_key_id = Uuid::new_v4();
        let encrypted_key = [99u8; PAGINATION_KEY_SIZE];

        let encrypt_svc = FixedKeyService::new(key_id, encrypted_key);
        let decrypt_svc = FixedKeyService::new(other_key_id, encrypted_key);

        let encrypt_paginator =
            OperationPaginator::new(&"test-service", &"ListItems", encrypt_svc.clone(), encrypt_svc).unwrap();
        let decrypt_paginator =
            OperationPaginator::new(&"test-service", &"ListItems", decrypt_svc.clone(), decrypt_svc).unwrap();

        let token = encrypt_paginator.encrypt_token(&"cursor").await.unwrap();
        let result: Result<String, _> = decrypt_paginator.decrypt_token(&token).await;
        assert!(result.is_err());
    }

