    #[test_log::test(tokio::test)]
    async fn test_caching_key_service_current_key() {
        let (key_id, _, svc) = make_fixed_key_service();
        let caching = CachingKeyService::new(svc.clone(), svc, NonZeroUsize::new(10).unwrap());
        let key = caching.clone().oneshot(()).await.unwrap();
        assert_eq!(key.key_id, key_id);
        // Second call should use the cache
        let key2 = caching.clone().oneshot(()).await.unwrap();
        assert_eq!(key2.key_id, key_id);
    }

